// 🔧 Build Gmail Query — [PRODUCT-PAID] Daily Fraud Scanner
const firstItem = $input.first();
// Skip if fired by Telegram handler path (Config fans out to both Build Gmail Query and Parse Input)
if (firstItem.json.message || firstItem.json.callback_query) return [];
const config = firstItem.json._config;
if (!config || !config.knownBanks) {
  throw new Error('⚙️ _config.knownBanks missing - wire ⚙️ Config upstream of this node');
}
const knownBanks = config.knownBanks.split(',').map(b => b.trim()).filter(Boolean);
const bankPatterns = '(' + knownBanks.join(' OR ') + ')';
// daysBack from ▶ Backfill (30/60/90); falls back to lookback_days from ⚙️ Config (90 = full)
const lookbackDays = parseInt(firstItem.json.daysBack) || parseInt(firstItem.json.lookback_days) || 30;
const now = new Date();
const lookbackDate = new Date(now.getTime() - lookbackDays * 24 * 60 * 60 * 1000);
const pad = n => String(n).padStart(2, '0');
const fmtDate = d => `${d.getFullYear()}/${pad(d.getMonth()+1)}/${pad(d.getDate())}`;
const fmtISO  = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const query = `${bankPatterns} after:${fmtDate(lookbackDate)}`;
return [{ json: { query, startDate: fmtISO(lookbackDate), endDate: fmtISO(now), lookbackDays, _config: config } }];

