// Config-driven setup (Product version)
const _cfg = $('⚙️ Config').first().json._config;
// Parse LLM response and enrich with email metadata
const input = $json;
const emailData = $('📝 Build Extraction Prompt').item.json;

let transaction;
try {
  let responseText = input.choices?.[0]?.message?.content || '';

  if (!input.choices || !input.choices[0]?.message?.content) {
    const errorMsg = input.error?.message || input.message || 'No response from LLM';
    throw new Error('API Error: ' + errorMsg);
  }

  responseText = responseText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

  let jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    const openBrace = responseText.indexOf('{');
    if (openBrace >= 0) {
      jsonMatch = (responseText.substring(openBrace) + '}').match(/\{[\s\S]*\}/);
    }
  }

  if (jsonMatch) {
    transaction = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No valid JSON found in response');
  }

  if (transaction.not_transaction === true) {
    return {json: {skip: true, not_transaction: true, emailId: emailData?.emailId || null}};
  }

  // Garbage filter: template values, Chinese responses, empty extractions
  const m = (transaction.merchant || '').toLowerCase();
  const isGarbage = (m === 'unknown' || m === 'null' || m === '' || m === 'n/a' ||
    m.includes('|') || m.startsWith('name of') || m.startsWith('extracted') ||
    m === '\u672a\u77e5' || m === '\u65e0' || m === '\u4e0d\u9002\u7528');
  if (isGarbage && (!transaction.amount || transaction.amount === 0)) {
    return {json: {skip: true, not_transaction: true, reason: 'garbage', emailId: emailData?.emailId || null}};
  }

} catch (e) {
  return {json: {error: true, message: 'Parse error: ' + e.message,
    rawResponse: (input.choices?.[0]?.message?.content || 'empty').substring(0, 200),
    emailId: emailData?.emailId || null}};
}

// Sanitize amount first - reject zero-amount unless transfer/dividend
if (transaction.amount === null || transaction.amount === undefined || isNaN(Number(transaction.amount))) {
  transaction.amount = 0;
} else {
  transaction.amount = Math.abs(Number(transaction.amount));
}
const keepZeroTypes = ['TRANSFER_IN','TRANSFER_OUT','DIVIDEND','TOP_UP','INVESTMENT'];
if (transaction.amount === 0 && !keepZeroTypes.includes(transaction.transaction_type)) {
  return {json: {skip: true, not_transaction: true, reason: 'zero_amount', emailId: emailData?.emailId || null}};
}

// Email date
let emailDateStr = '';
const rawDate = emailData?.emailDateRaw || '';
if (rawDate) {
  try {
    const parsed = new Date(rawDate);
    if (!isNaN(parsed.getTime())) emailDateStr = parsed.toISOString().split('T')[0];
  } catch(e) {}
}
if (!emailDateStr) emailDateStr = new Date().toISOString().split('T')[0];

transaction.emailDate = emailDateStr;
transaction.gmailUrl = 'https://mail.google.com/mail/u/0/#inbox/' + (emailData?.emailId || transaction.emailId || '');
if (!transaction.emailId) transaction.emailId = emailData?.emailId || '';

// Helper: detect bad values
function isBad(val) {
  if (!val) return true;
  const s = val.toLowerCase();
  return s.includes('|') || s === 'unknown' || s === 'null' || s === 'n/a' ||
    s.startsWith('name of') || s.startsWith('actual') || s.startsWith('extracted') ||
    s === 'bank name' || s === 'merchant name' ||
    s === '\u672a\u77e5' || s === '\u65e0' || s === '\u4e0d\u9002\u7528';
}

// Known banks list for validation
const KNOWN_BANKS = _cfg ? _cfg.knownBanks.split(',').map(b => b.trim()).filter(Boolean) : ['Chase', 'Bank of America', 'Wells Fargo'];

// Bank inference from email metadata
function inferBank(combined) {
  const c = combined.toLowerCase();
  if (c.includes('dbs') || c.includes('posb')) return 'DBS';
  if (c.includes('uob')) return 'UOB';
  if (c.includes('ocbc')) return 'OCBC';
  if (c.includes('hsbc')) return 'HSBC';
  if (c.includes('citibank') || c.includes('citi ')) return 'Citibank';
  if (c.includes('standard chartered') || c.includes('scb')) return 'Standard Chartered';
  if (c.includes('gxs')) return 'GXS';
  if (c.includes('trust bank')) return 'Trust Bank';
  if (c.includes('youtrip')) return 'YouTrip';
  if (c.includes('revolut')) return 'Revolut';
  if (c.includes('wise.com') || c.includes('transferwise')) return 'Wise';
  if (c.includes('grab')) return 'Grab';
  if (c.includes('moomoo') || c.includes('futu')) return 'Moomoo';
  if (c.includes('ibkr') || c.includes('interactive broker')) return 'IBKR';
  if (c.includes('tiger broker') || c.includes('tigerbrokers')) return 'Tiger Brokers';
  if (c.includes('aia')) return 'AIA';
  if (c.includes('prudential')) return 'Prudential';
  if (c.includes('great eastern')) return 'Great Eastern';
  if (c.includes('income insurance') || c.includes('ntuc income')) return 'Income';
  if (c.includes('fwd')) return 'FWD';
  if (c.includes('paypal')) return 'PayPal';
  if (c.includes('apple')) return 'Apple';
  if (c.includes('paynow') || c.includes('nets')) return 'DBS';
  return null;
}

// Sanitize bank - validate against known list, then infer
const llmBank = (transaction.bank || '').trim();
const isKnownBank = KNOWN_BANKS.some(b => b.toLowerCase() === llmBank.toLowerCase());

if (!isKnownBank || isBad(llmBank)) {
  // LLM bank not recognized - infer from email metadata
  const fromStr = emailData?.emailFrom || '';
  const subjStr = emailData?.emailSubject || '';
  const combined = fromStr + ' ' + subjStr;
  const inferred = inferBank(combined);
  if (inferred) {
    transaction.bank = inferred;
  } else {
    // Try the prompt text itself (contains email body)
    const promptText = emailData?.extractPrompt || '';
    const inferredFromBody = inferBank(promptText);
    if (inferredFromBody) {
      transaction.bank = inferredFromBody;
    } else if (!isBad(llmBank)) {
      // Keep LLM's answer if it's not garbage (might be a bank we don't know)
      transaction.bank = llmBank;
    } else {
      transaction.bank = 'Unknown';
    }
  }
}

// Sanitize merchant
if (isBad(transaction.merchant)) {
  const subject = emailData?.emailSubject || '';
  if (subject && subject.length > 3) {
    transaction.merchant = subject.substring(0, 50);
  } else {
    transaction.merchant = 'Unidentified';
  }
}

// Sanitize currency
if (!transaction.currency || transaction.currency.length > 3 || transaction.currency.includes('|')) {
  transaction.currency = (_cfg && _cfg.currency ? _cfg.currency : 'USD');
}

// Sanitize transaction_type
const validTypes = ['SPENDING','TOP_UP','WITHDRAWAL','TRANSFER_IN','TRANSFER_OUT','INVESTMENT','DIVIDEND','INSURANCE_PAYMENT','SUBSCRIPTION','FEES','OTHER'];
if (!transaction.transaction_type || !validTypes.includes(transaction.transaction_type)) {
  transaction.transaction_type = 'OTHER';
}

// Sanitize transaction_date - year range 2024+
if (transaction.transaction_date) {
  const pd = new Date(transaction.transaction_date);
  const y = pd.getFullYear();
  if (isNaN(pd.getTime()) || y < 2024 || y > new Date().getFullYear() + 1) {
    transaction.transaction_date = emailDateStr;
  }

  // Validate transaction_date is a real date (e.g., no Feb 29 in non-leap years)
  if (transaction.transaction_date) {
    const dtStr = String(transaction.transaction_date).substring(0, 10);
    const testDate = new Date(dtStr + 'T00:00:00Z');
    if (isNaN(testDate.getTime()) || testDate.toISOString().substring(0, 10) !== dtStr) {
      // Invalid date - try fixing common issues
      const parts = dtStr.split('-');
      if (parts.length === 3) {
        const y = parseInt(parts[0]), m = parseInt(parts[1]), d = parseInt(parts[2]);
        // Get last valid day of the month
        const lastDay = new Date(y, m, 0).getDate();
        const fixedDay = Math.min(d, lastDay);
        transaction.transaction_date = y + '-' + String(m).padStart(2,'0') + '-' + String(fixedDay).padStart(2,'0');
      } else {
        transaction.transaction_date = emailDateStr;
      }
    }
  }

} else {
  transaction.transaction_date = emailDateStr;
}

// Sanitize purchase_category
const validCats = ['food','transport','shopping','entertainment','utilities','health','insurance','education','investment','other'];
if (!transaction.purchase_category || !validCats.includes(transaction.purchase_category)) {
  transaction.purchase_category = 'other';
}

return { json: transaction };

// 🔍 Anomaly Detection v5 — [PRODUCT-PAID] Daily Fraud Scanner
// 4-layer: Universal → Statistical Baseline → Tier-Based → Contextual
const tierItems = $input.all();         // tier data from Fetch Merchant Tier & Stats
const txnItems  = $('💾 Store Transaction').all(); // original transaction data
const config    = $('⚙️ Config').first().json._config;

const results = [];
for (let i = 0; i < tierItems.length; i++) {
  const tierData = tierItems[i].json;
  const txn      = (txnItems[i] || txnItems[0]).json;

  const amount           = parseFloat(txn.amount) || 0;
  const transactionType  = (txn.transaction_type || '').toUpperCase();
  const purchaseCategory = (txn.purchase_category || 'other').toLowerCase();
  const tier             = tierData.tier || 'GREY';
  const trustScore       = parseInt(tierData.trust_score) || 0;
  const isNewMerchant    = String(tierData.is_new_merchant) === 'true' || tierData.is_new_merchant === true;
  const velocityToday    = parseInt(tierData.velocity_today) || 0;
  const categoryStatsJson = tierData.category_stats_json || '{}';

  let riskScore = 0;
  const riskFactors = [];

  // === LAYER 1: Universal Rules ===
  if (amount === 0 && transactionType !== 'INVESTMENT' && transactionType !== 'DIVIDEND') {
    results.push({ json: { ...txn, merchantTier: tier, trustScore, riskScore: 0,
      riskFactors: [], isFlagged: false, flagReason: 'Zero amount - skipped',
      detectedAt: new Date().toISOString() }});
    continue;
  }

  const txnDateStr = txn.transaction_date || txn.date || new Date().toISOString().split('T')[0];
  const txnDate = new Date(txnDateStr + 'T12:00:00Z');
  const daysDiff = (Date.now() - txnDate.getTime()) / (1000 * 60 * 60 * 24);
  if (daysDiff > 30 && transactionType !== 'INVESTMENT' && transactionType !== 'DIVIDEND') {
    results.push({ json: { ...txn, merchantTier: tier, trustScore, riskScore: 0,
      riskFactors: [], isFlagged: false, flagReason: 'Historical (>30 days) - skipped',
      detectedAt: new Date().toISOString() }});
    continue;
  }

  if (transactionType === 'INVESTMENT' || transactionType === 'DIVIDEND') {
    riskScore += 50;
    riskFactors.push({ factor: transactionType + ' transaction', points: 50 });
  }
  if (transactionType === 'INSURANCE_CLAIM' || purchaseCategory === 'insurance') {
    riskScore += 40;
    riskFactors.push({ factor: 'Insurance claim/deposit', points: 40 });
  }

  // === LAYER 2: Statistical Baseline ===
  let categoryStats = {};
  try { categoryStats = typeof categoryStatsJson === 'string' ? JSON.parse(categoryStatsJson) : (categoryStatsJson || {}); } catch(e) {}
  const stats = categoryStats[purchaseCategory];
  const hasStats = stats && parseInt(stats.count) >= 10;

  if (hasStats) {
    const mean   = parseFloat(stats.mean)   || 0;
    const stddev = parseFloat(stats.stddev) || 0;
    const q3     = parseFloat(stats.q3)     || 0;
    const iqr    = parseFloat(stats.iqr)    || 0;
    if (stddev > 0) {
      const zScore = (amount - mean) / stddev;
      if (Math.abs(zScore) > 3) {
        riskScore += 30; riskFactors.push({ factor: 'Z-score: ' + zScore.toFixed(1) + ' (>3σ)', points: 30 });
      } else if (Math.abs(zScore) > 2) {
        riskScore += 15; riskFactors.push({ factor: 'Z-score: ' + zScore.toFixed(1) + ' (>2σ)', points: 15 });
      }
      if (mean > 0 && Math.abs(amount - mean) / mean < 0.10) {
        riskScore -= 10; riskFactors.push({ factor: 'Recurring amount pattern', points: -10 });
      }
    }
    if (iqr > 0) {
      if (amount > q3 + 3.0 * iqr) {
        riskScore += 30; riskFactors.push({ factor: 'IQR extreme outlier (3.0×)', points: 30 });
      } else if (amount > q3 + 1.5 * iqr) {
        riskScore += 15; riskFactors.push({ factor: 'IQR moderate outlier (1.5×)', points: 15 });
      }
    }
  } else {
    const highValue    = parseInt(config.highValueThreshold)    || 1000;
    const extremeValue = parseInt(config.extremeValueThreshold) || 5000;
    if (amount >= extremeValue) {
      riskScore += 30; riskFactors.push({ factor: 'Extreme amount (' + config.currency + ' ' + extremeValue + '+)', points: 30 });
    } else if (amount >= highValue) {
      riskScore += 25; riskFactors.push({ factor: 'High value (' + config.currency + ' ' + highValue + '+)', points: 25 });
    }
  }

  // === LAYER 3: Tier-Based ===
  if (tier === 'GOLD') {
    riskScore -= 15; riskFactors.push({ factor: 'Trusted GOLD merchant', points: -15 });
  } else if (tier === 'GREY') {
    riskScore += 20; riskFactors.push({ factor: 'Unknown/GREY merchant', points: 20 });
  }
  if (isNewMerchant) {
    riskScore += 10; riskFactors.push({ factor: 'First-time merchant', points: 10 });
  }

  // === LAYER 4: Contextual ===
  const txnHour      = txnDate.getUTCHours();
  const tzOffset     = parseInt(config.timezoneOffset) || 0;
  const localHour    = (txnHour + tzOffset + 24) % 24;
  const unusualStart = config.unusualHoursStart != null ? config.unusualHoursStart : 0;
  const unusualEnd   = config.unusualHoursEnd   != null ? config.unusualHoursEnd   : 6;
  if (localHour >= unusualStart && localHour < unusualEnd) {
    riskScore += 15; riskFactors.push({ factor: 'Unusual hour: ' + localHour + ':00 local', points: 15 });
  }
  const goldCap = parseInt(config.goldFrequencyCap) || 5;
  const velCap  = tier === 'GOLD' ? goldCap : 3;
  if (velocityToday > velCap) {
    riskScore += 10; riskFactors.push({ factor: 'High frequency: ' + velocityToday + ' txns today', points: 10 });
  }

  // === Final Score ===
  const finalScore     = Math.max(0, Math.min(100, riskScore));
  const alertThreshold = parseInt(config.alertRiskThreshold) || 50;
  const isFlagged      = finalScore >= alertThreshold;
  const flagReason = riskFactors.length > 0
    ? riskFactors.map(f => f.factor + ' (' + (f.points > 0 ? '+' : '') + f.points + ')').join('; ')
    : (isFlagged ? 'Risk score: ' + finalScore : 'Below threshold');

  results.push({ json: {
    ...txn,
    merchantTier: tier,
    trustScore,
    riskScore:   finalScore,
    riskFactors,
    isFlagged,
    flagReason,
    detectedAt:  new Date().toISOString()
  }});
}
return results;

