// ⚙️ Config — Detect fraud transaction using AI risk-scoring (Dashboard Included)
// ====================================================================
// 👋 NEW TO THIS WORKFLOW?
// 1. Read every comment below — each value has a "*From:" neighbor
//    telling you exactly where/how to obtain it.
// 2. Replace every YOUR_* value with your own.
// 3. Pick ONE LLM provider (default = OpenRouter, cheapest path).
// 4. Save the Config node, then connect credentials on the red-bordered
//    nodes, then send /setup to your Telegram bot to create the
//    fraud_detection Postgres schema, then click ▶ Backfill 30 Days.
// ====================================================================

const CONFIG = {

  // ─── 📱 Telegram (for fraud alerts + LEGIT/FRAUD button responses) ─────
  // The chat ID is WHERE alerts go. The bot token (set in the Telegram
  // credential, not here) is WHO sends them.
  chatIdFrom:     'message @userinfobot on Telegram - it replies with your numeric chat ID',
  botTokenFrom:   'message @BotFather on Telegram - send /newbot, follow prompts, paste the token into the Telegram Bot credential in n8n',
  telegramChatId: 'YOUR_TELEGRAM_CHAT_ID',

  // ─── 🌏 Locale / Timing ─────────────────────────────────────────
  // Used by anomaly detection (unusual-hours rule) and dashboard labels.
  // timezoneOffset = hours from UTC (e.g. Singapore = +8, US Eastern = -5).
  timezone:        'Asia/Singapore',
  timezoneOffset:  8,
  currency:        'SGD',

  // ─── 🚨 Risk Thresholds (tune to your spending profile) ──────────────
  // Layer 1 universal rules in the Anomaly Detection node:
  highValueThreshold:    1000,   // any single txn >= this triggers a flag review
  extremeValueThreshold: 5000,   // any single txn >= this is always alerted
  unusualHoursStart:     0,      // 0=midnight; transactions between Start-End trigger flag
  unusualHoursEnd:       6,      // i.e. 12am-6am local time
  goldFrequencyCap:      5,      // GOLD-tier merchants get an exception up to N txns/day
  alertRiskThreshold:    50,     // final risk score (0-100) >= this fires a Telegram alert

  // ─── 🏦 Known Banks (comma-separated keywords matched in Gmail sender / subject) ───
  // The scanner only processes emails matching these patterns. Add your bank's name
  // exactly as it appears in transaction notification emails.
  // Singapore examples: 'DBS,OCBC,UOB,IBKR'
  // US examples:        'Chase,Capital One,Wells Fargo,Bank of America'
  // UK examples:        'HSBC,Barclays,Monzo,Starling,Revolut'
  knownBanks: 'DBS,OCBC,UOB,IBKR',

  // ─── 🤖 LLM API (OpenAI-compatible) ──────────────────────────────────
  // Pick ONE provider. Default = OpenRouter (cheapest with Mistral Nemo).
  // To switch: comment out the active 3 lines below, uncomment your chosen block.

  // ✅ Option 1: OpenRouter — multi-model gateway, ~$0.0001 per email on Mistral Nemo
  keyFrom:    'https://openrouter.ai/keys (sign up free, add ~$5 credit to start; covers a year of daily polling)',
  llmBaseUrl: 'https://openrouter.ai/api/v1/chat/completions',
  llmModel:   'mistralai/mistral-nemo',

  // Option 2: OpenAI direct
  // keyFrom:    'https://platform.openai.com/api-keys',
  // llmBaseUrl: 'https://api.openai.com/v1/chat/completions',
  // llmModel:   'gpt-4o-mini',

  // Option 3: Google Gemini direct — free tier available
  // keyFrom:    'https://aistudio.google.com/apikey (free tier sufficient for personal use)',
  // llmBaseUrl: 'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions',
  // llmModel:   'gemini-2.0-flash',

  // Option 4: Groq — fastest inference, free tier
  // keyFrom:    'https://console.groq.com/keys (free tier, rate-limited)',
  // llmBaseUrl: 'https://api.groq.com/openai/v1/chat/completions',
  // llmModel:   'llama-3.3-70b-versatile',

  // Option 5: Ollama — local LLM, no cost, full privacy
  // keyFrom:    'no key needed - install: https://ollama.com then run: ollama pull qwen2.5:7b',
  // llmBaseUrl: 'http://host.docker.internal:11434/v1/chat/completions',
  // llmModel:   'qwen2.5:7b',

  // ─── 📧 Bank Discovery (Weekly Bank Detector path - currently disabled) ──
  // When you enable the Sunday Trigger, weekly summaries get emailed here.
  emailFrom:              'this is the recipient address that will receive weekly summary emails',
  summaryEmailRecipient:  'YOUR_EMAIL@EXAMPLE.COM',

  // ─── 🌐 Your n8n domain (for self-referencing dashboard links in alerts) ──
  // Used by the /setup wizard to print the correct dashboard URL.
  // Example: 'n8n.example.com' (no protocol, no path).
  n8nDomainFrom: 'your own n8n instance hostname',
  n8nDomain:     'YOUR_N8N_DOMAIN',
};
// ====================================================================

const items = $input.all();
if (items.length === 0) return [];
return items.map(item => ({ json: { ...item.json, _config: CONFIG, lookback_days: 90 } }));

// Handle both text messages and callback queries
// Product v1: Added /setup, /reconfigure, SETUP_* wizard callbacks
const rawData = $input.first().json;
// Skip if fired by scanner/backfill path (Config fans out to both Parse Input and Build Gmail Query)
if (!rawData.message && !rawData.callback_query) return [];
const callbackQuery = rawData.callback_query;
const message = rawData.message;

// Callback query from button press
if (callbackQuery && callbackQuery.data) {
  const data = callbackQuery.data;

  // Setup wizard callbacks (SETUP_*)
  if (data.startsWith('SETUP_')) {
    return [{ json: {
      hasCallback: true,
      action: data,
      actionType: 'setup',
      callbackQueryId: callbackQuery.id,
      chatId: callbackQuery.message?.chat?.id,
      messageId: callbackQuery.message?.message_id,
      valid: true
    }}];
  }

  // Match: ACTION_ID (LEGIT, FRAUD, DETAILS, FALSE_ALERT, GOLD, SILVER, GREY, APPLY_FIX)
  const match = data.match(/^(LEGIT|FRAUD|DETAILS|FALSE_ALERT|GOLD|SILVER|GREY|APPLY_FIX)_(\d+)$/i);

  if (!match) {
    return [{ json: {
      hasCallback: true,
      action: 'ACK',
      callbackQueryId: callbackQuery.id,
      chatId: callbackQuery.message?.chat?.id,
      messageId: callbackQuery.message?.message_id,
      valid: false,
      flagId: null
    }}];
  }

  const action = match[1].toUpperCase();
  const flagId = parseInt(match[2]);

  let actionType = 'response';
  if (['GOLD', 'SILVER', 'GREY'].includes(action)) {
    actionType = 'tier_assign';
  } else if (action === 'FALSE_ALERT') {
    actionType = 'false_alert';
  } else if (action === 'APPLY_FIX') {
    actionType = 'apply_fix';
  }

  return [{ json: {
    hasCallback: true,
    action,
    actionType,
    flagId,
    callbackQueryId: callbackQuery.id,
    chatId: callbackQuery.message?.chat?.id,
    messageId: callbackQuery.message?.message_id,
    valid: true
  }}];
}

// Text message handling
const text = message?.text || message?.caption || '';
const chatId = message?.chat?.id;

// Setup/reconfigure commands
if (text.trim() === '/setup') {
  return [{ json: { hasCallback: false, chatId, action: 'setup', actionType: 'setup', isHelp: false } }];
}
if (text.trim() === '/reconfigure') {
  return [{ json: { hasCallback: false, chatId, action: 'reconfigure', actionType: 'reconfigure', isHelp: false } }];
}

// LEGIT/FRAUD text reply
const match = text.match(/^(LEGIT|FRAUD)\s+(\d+)/i);
if (!match) {
  return [{ json: {
    hasCallback: false,
    chatId,
    text: "❌ Invalid format.\n\nCommands:\n• /setup — first-time setup\n• /reconfigure — update settings\n\nOr reply: LEGIT <id> or FRAUD <id>",
    isHelp: true,
    flagId: null,
    action: null
  }}];
}

const action = match[1].toUpperCase();
const flagId = parseInt(match[2]);
return [{ json: {
  hasCallback: false,
  action,
  actionType: 'response',
  flagId,
  chatId,
  messageId: null,
  originalMessage: text,
  isHelp: false,
  callbackQueryId: null
}}];

// Analyze false alert and suggest fix
const parseData = $('📊 Parse Input (Text or Callback)').first().json;
const txnData = $('🔍 Fetch Transaction').first().json;

const merchant = txnData.merchant || 'Unknown';
const amount = parseFloat(txnData.amount) || 0;
const txnType = txnData.transaction_type || 'OTHER';
const category = txnData.purchase_category || 'other';
const flagReason = txnData.flag_reason || '';

// Analyze the false alert
let analysis = [];
let suggestedTier = 'SILVER';
let suggestedSettings = {};

// Check if subscription type
if (txnType === 'SUBSCRIPTION') {
  analysis.push('• SUBSCRIPTION type - automated recurring charge');
  suggestedTier = 'GOLD';
  suggestedSettings.frequencyCap = 5;
  suggestedSettings.amountCeiling = (amount * 1.2).toFixed(2);
}

// Check if transport category
if (category === 'transport') {
  analysis.push('• TRANSPORT category - variable amounts expected');
  suggestedTier = 'SILVER';
  suggestedSettings.frequencyCap = 10;
}

// Check if P2P transfer
if (['TRANSFER_IN', 'TRANSFER_OUT'].includes(txnType)) {
  analysis.push('• P2P transfer - legitimate person-to-person');
  suggestedTier = 'SILVER';
  suggestedSettings.frequencyCap = 20;
}

// Default recommendation
if (analysis.length === 0) {
  analysis.push('• Regular merchant transaction');
  suggestedTier = 'SILVER';
  suggestedSettings.frequencyCap = 10;
  suggestedSettings.amountCeiling = (amount * 2).toFixed(2);
}

const tierEmoji = { GOLD: '🥇', SILVER: '🥈', GREY: '🩶' };

return [{
  json: {
    flagId: parseData.flagId,
    chatId: parseData.chatId,
    messageId: parseData.messageId,
    callbackQueryId: parseData.callbackQueryId,
    merchant: merchant,
    amount: amount,
    txnType: txnType,
    category: category,
    flagReason: flagReason,
    analysis: analysis.join('\n'),
    suggestedTier: suggestedTier,
    suggestedTierEmoji: tierEmoji[suggestedTier],
    suggestedSettings: suggestedSettings,
    txnData: txnData
  }
}];

