const staticData = $getWorkflowStaticData('global');
const input = $input.first().json;
const chatId = String(input.chatId || '');
const action = input.action || '';

if (!chatId) return [{ json: { chatId, wizardAction: 'error', message: 'No chatId' } }];
if (!staticData.setupSessions) staticData.setupSessions = {};

const CITIES = {
  Singapore: { iana: 'Asia/Singapore', offset: 8, label: 'Singapore (SGT)', region: 'ASIA' },
  Hong_Kong: { iana: 'Asia/Hong_Kong', offset: 8, label: 'Hong Kong (HKT)', region: 'ASIA' },
  Tokyo: { iana: 'Asia/Tokyo', offset: 9, label: 'Tokyo (JST)', region: 'ASIA' },
  Sydney: { iana: 'Australia/Sydney', offset: 11, label: 'Sydney (AEDT)', region: 'ASIA' },
  Bangkok: { iana: 'Asia/Bangkok', offset: 7, label: 'Bangkok (ICT)', region: 'ASIA' },
  Mumbai: { iana: 'Asia/Kolkata', offset: 5.5, label: 'Mumbai (IST)', region: 'ASIA' },
  Manila: { iana: 'Asia/Manila', offset: 8, label: 'Manila (PHT)', region: 'ASIA' },
  Jakarta: { iana: 'Asia/Jakarta', offset: 7, label: 'Jakarta (WIB)', region: 'ASIA' },
  Seoul: { iana: 'Asia/Seoul', offset: 9, label: 'Seoul (KST)', region: 'ASIA' },
  Taipei: { iana: 'Asia/Taipei', offset: 8, label: 'Taipei (CST)', region: 'ASIA' },
  Kuala_Lumpur: { iana: 'Asia/Kuala_Lumpur', offset: 8, label: 'Kuala Lumpur (MYT)', region: 'ASIA' },
  Dubai: { iana: 'Asia/Dubai', offset: 4, label: 'Dubai (GST)', region: 'ASIA' },
  New_York: { iana: 'America/New_York', offset: -5, label: 'New York (ET)', region: 'AMERICAS' },
  Los_Angeles: { iana: 'America/Los_Angeles', offset: -8, label: 'Los Angeles (PT)', region: 'AMERICAS' },
  Chicago: { iana: 'America/Chicago', offset: -6, label: 'Chicago (CT)', region: 'AMERICAS' },
  Toronto: { iana: 'America/Toronto', offset: -5, label: 'Toronto (ET)', region: 'AMERICAS' },
  Sao_Paulo: { iana: 'America/Sao_Paulo', offset: -3, label: 'Sao Paulo (BRT)', region: 'AMERICAS' },
  Mexico_City: { iana: 'America/Mexico_City', offset: -6, label: 'Mexico City (CST)', region: 'AMERICAS' },
  London: { iana: 'Europe/London', offset: 0, label: 'London (GMT)', region: 'EUROPE' },
  Paris: { iana: 'Europe/Paris', offset: 1, label: 'Paris (CET)', region: 'EUROPE' },
  Berlin: { iana: 'Europe/Berlin', offset: 1, label: 'Berlin (CET)', region: 'EUROPE' },
  Moscow: { iana: 'Europe/Moscow', offset: 3, label: 'Moscow (MSK)', region: 'EUROPE' },
  Cairo: { iana: 'Africa/Cairo', offset: 2, label: 'Cairo (EET)', region: 'EUROPE' },
  Johannesburg: { iana: 'Africa/Johannesburg', offset: 2, label: 'Johannesburg (SAST)', region: 'EUROPE' },
  Lagos: { iana: 'Africa/Lagos', offset: 1, label: 'Lagos (WAT)', region: 'EUROPE' }
};

const CITIES_BY_REGION = {
  ASIA: Object.entries(CITIES).filter(([,v]) => v.region === 'ASIA').map(([k]) => k),
  AMERICAS: Object.entries(CITIES).filter(([,v]) => v.region === 'AMERICAS').map(([k]) => k),
  EUROPE: Object.entries(CITIES).filter(([,v]) => v.region === 'EUROPE').map(([k]) => k)
};

function buildMessage(wizardAction, s) {
  let messageText = 'Processing...';
  let replyMarkup = null;

  if (wizardAction === 'db_check') {
    if (s.mode === 'reconfigure') {
      messageText = 'Reconfigure Finance Tracker\n\nYour data is preserved. Choose what to update.\n\n[Step 1 of 7]';
      replyMarkup = JSON.stringify({ inline_keyboard: [[
        { text: 'Update settings', callback_data: 'SETUP_SKIP_DB' },
        { text: 'Cancel', callback_data: 'SETUP_DB_CONFIRM_NO' }
      ]] });
    } else {
      messageText = 'Finance Tracker Setup\n\nChecking database...\n\n[Step 1 of 7]';
      replyMarkup = JSON.stringify({ inline_keyboard: [[
        { text: 'Yes, start fresh', callback_data: 'SETUP_DB_CONFIRM_YES' },
        { text: 'Cancel', callback_data: 'SETUP_DB_CONFIRM_NO' }
      ]] });
    }
  } else if (wizardAction === 'show_region') {
    messageText = 'Select your region\n\n[Step 2 of 7]';
    replyMarkup = JSON.stringify({ inline_keyboard: [
      [{ text: 'Asia/Pacific', callback_data: 'SETUP_REGION_ASIA' }],
      [{ text: 'Americas', callback_data: 'SETUP_REGION_AMERICAS' }],
      [{ text: 'Europe/Africa', callback_data: 'SETUP_REGION_EUROPE' }]
    ]});
  } else if (wizardAction === 'show_city') {
    messageText = 'Select your city (' + s.region + ')\n\n[Step 3 of 7]';
    const cities = s.cities || [];
    const labels = s.cityLabels || cities;
    const rows = [];
    for (let i = 0; i < cities.length; i += 2) {
      const row = [{ text: labels[i], callback_data: 'SETUP_CITY_' + cities[i] }];
      if (cities[i+1]) row.push({ text: labels[i+1], callback_data: 'SETUP_CITY_' + cities[i+1] });
      rows.push(row);
    }
    replyMarkup = JSON.stringify({ inline_keyboard: rows });
  } else if (wizardAction === 'confirm_tz') {
    const offsetStr = s.utcOffset >= 0 ? 'UTC+' + s.utcOffset : 'UTC' + s.utcOffset;
    messageText = 'Timezone Confirmation\n\nCity: ' + s.cityLabel + '\nTimezone: ' + s.ianaTimezone + ' (' + offsetStr + ')\nDaily scan: 6:00 AM local\n\nConfirm?\n\n[Step 4 of 7]';
    replyMarkup = JSON.stringify({ inline_keyboard: [[
      { text: 'Confirm', callback_data: 'SETUP_CONFIRM_TZ' },
      { text: 'Change region', callback_data: 'SETUP_REGION_BACK' }
    ]] });
  } else if (wizardAction === 'show_threshold') {
    messageText = 'High-Value Alert Threshold\n\nTransactions above this amount will trigger alerts regardless of merchant tier.\n\n[Step 5 of 7]';
    replyMarkup = JSON.stringify({ inline_keyboard: [
      [{ text: '$500', callback_data: 'SETUP_THRESH_500' }, { text: '$1,000', callback_data: 'SETUP_THRESH_1000' }],
      [{ text: '$2,000', callback_data: 'SETUP_THRESH_2000' }, { text: '$5,000', callback_data: 'SETUP_THRESH_5000' }]
    ]});
  } else if (wizardAction === 'show_llm') {
    messageText = 'LLM Provider\n\nChoose your AI provider for transaction extraction.\n\n[Step 6 of 7]';
    replyMarkup = JSON.stringify({ inline_keyboard: [
      [{ text: 'Ollama (Free, local)', callback_data: 'SETUP_LLM_ollama' }],
      [{ text: 'OpenRouter (~$3/mo)', callback_data: 'SETUP_LLM_openrouter' }],
      [{ text: 'OpenAI (~$5/mo)', callback_data: 'SETUP_LLM_openai' }]
    ]});
  } else if (wizardAction === 'show_summary') {
    messageText = 'Setup Summary\n\nTimezone: ' + s.cityLabel + '\nScan: 6:00 AM daily (' + s.scanCronUTC + ')\nAlert threshold: $' + s.highValueThreshold + '\nLLM: ' + s.llmChoice + '\n\nProceed?\n\n[Step 7 of 7]';
    replyMarkup = JSON.stringify({ inline_keyboard: [[
      { text: 'Confirm & Setup', callback_data: 'SETUP_FINAL_CONFIRM' },
      { text: 'Go back', callback_data: 'SETUP_REGION_BACK' }
    ]] });
  } else if (wizardAction === 'cancelled') {
    messageText = s.message || 'Setup cancelled.';
  } else if (wizardAction === 'no_session') {
    messageText = s.message || 'No active session. Send /setup to begin.';
  }

  return { messageText, replyMarkup };
}

// Expire old sessions (>30 min)
const now = Date.now();
for (const [id, sess] of Object.entries(staticData.setupSessions)) {
  if (now - (sess.startedAt || 0) > 30 * 60 * 1000) delete staticData.setupSessions[id];
}

if (action === 'setup' || action === 'reconfigure') {
  const sessionData = {
    step: 'db_check', mode: action,
    region: null, city: null, ianaTimezone: null, utcOffset: null,
    scanCronUTC: null, highValueThreshold: 1000, llmChoice: null,
    startedAt: now
  };
  staticData.setupSessions[chatId] = sessionData;
  const msg = buildMessage('db_check', { ...sessionData, mode: action });
  return [{ json: { ...sessionData, chatId, wizardAction: 'db_check', mode: action, ...msg } }];
}

const sess = staticData.setupSessions[chatId];
if (!sess) {
  const noSessData = { chatId, wizardAction: 'no_session', message: 'No active setup session. Send /setup to begin.' };
  const msg = buildMessage('no_session', noSessData);
  return [{ json: { ...noSessData, ...msg } }];
}

if (!action.startsWith('SETUP_')) {
  return [{ json: { chatId, wizardAction: 'ignore' } }];
}

if (action === 'SETUP_DB_CONFIRM_YES') {
  sess.step = 'region'; sess.dropExisting = true;
  const msg = buildMessage('show_region', sess);
  return [{ json: { ...sess, chatId, wizardAction: 'show_region', ...msg } }];
}
if (action === 'SETUP_DB_CONFIRM_NO') {
  delete staticData.setupSessions[chatId];
  const cancelData = { chatId, wizardAction: 'cancelled', message: 'Setup cancelled. Use /reconfigure to update settings only.' };
  const msg = buildMessage('cancelled', cancelData);
  return [{ json: { ...cancelData, ...msg } }];
}
if (action === 'SETUP_SKIP_DB') {
  sess.step = 'region';
  const msg = buildMessage('show_region', sess);
  return [{ json: { ...sess, chatId, wizardAction: 'show_region', ...msg } }];
}
if (action.startsWith('SETUP_REGION_')) {
  const region = action.replace('SETUP_REGION_', '');
  if (region === 'BACK') {
    sess.step = 'region';
    const msg = buildMessage('show_region', sess);
    return [{ json: { ...sess, chatId, wizardAction: 'show_region', ...msg } }];
  }
  sess.region = region; sess.step = 'city';
  const cityData = {
    ...sess, chatId, wizardAction: 'show_city',
    cities: CITIES_BY_REGION[region] || [],
    cityLabels: (CITIES_BY_REGION[region] || []).map(k => CITIES[k] ? CITIES[k].label : k)
  };
  const msg = buildMessage('show_city', cityData);
  return [{ json: { ...cityData, ...msg } }];
}
if (action.startsWith('SETUP_CITY_')) {
  const cityKey = action.replace('SETUP_CITY_', '');
  const city = CITIES[cityKey];
  if (city) {
    sess.city = cityKey; sess.cityLabel = city.label;
    sess.ianaTimezone = city.iana; sess.utcOffset = city.offset;
    const utcHour = (((6 - city.offset) % 24) + 24) % 24;
    sess.scanCronUTC = '0 ' + Math.floor(utcHour) + ' * * *';
    sess.step = 'confirm_tz';
    const msg = buildMessage('confirm_tz', sess);
    return [{ json: { ...sess, chatId, wizardAction: 'confirm_tz', ...msg } }];
  }
}
if (action === 'SETUP_CONFIRM_TZ') {
  sess.step = 'threshold';
  const msg = buildMessage('show_threshold', sess);
  return [{ json: { ...sess, chatId, wizardAction: 'show_threshold', ...msg } }];
}
if (action.startsWith('SETUP_THRESH_')) {
  sess.highValueThreshold = parseInt(action.replace('SETUP_THRESH_', ''));
  sess.step = 'llm';
  const msg = buildMessage('show_llm', sess);
  return [{ json: { ...sess, chatId, wizardAction: 'show_llm', ...msg } }];
}
if (action.startsWith('SETUP_LLM_')) {
  sess.llmChoice = action.replace('SETUP_LLM_', '');
  sess.step = 'confirm';
  const msg = buildMessage('show_summary', sess);
  return [{ json: { ...sess, chatId, wizardAction: 'show_summary', ...msg } }];
}
if (action === 'SETUP_FINAL_CONFIRM') {
  sess.step = 'saving';
  return [{ json: { ...sess, chatId, wizardAction: 'save_config' } }];
}

return [{ json: { chatId, wizardAction: 'unknown_callback', action } }];

// Update Daily Fraud Scanner and Weekly Bank Detector cron schedules
// via n8n REST API (internal)
const sess = $('⚙️ Setup State').first().json;
const newCron = sess.scanCronUTC; // e.g. "0 22 * * *"

// Note: buyers need to update workflow IDs below to match their imported workflows
const FRAUD_SCANNER_ID = 'REPLACE_WITH_FRAUD_SCANNER_WORKFLOW_ID';
const N8N_API_KEY = 'YOUR_N8N_API_KEY'; // Set in n8n environment variables

// Skip if no valid cron
if (!newCron || newCron === 'undefined') {
  return [{ json: { updated: false, message: 'No cron to update' } }];
}

return [{ json: {
  updated: false,
  message: 'Schedule update: set FRAUD_SCANNER_ID and N8N_API_KEY env vars',
  targetCron: newCron
}}];

const now = new Date();
const weekAgo = new Date(now);
weekAgo.setDate(weekAgo.getDate() - 7);
const fmt = (d) => d.getFullYear() + '/' + String(d.getMonth() + 1).padStart(2, '0') + '/' + String(d.getDate()).padStart(2, '0');
const keywords = '(transaction OR receipt OR payment OR purchase OR charged OR debit OR credit OR bank OR card OR insurance OR investment OR dividend OR claim OR payout OR deposit)';
const query = keywords + ' after:' + fmt(weekAgo) + ' before:' + fmt(now);
return [{ json: { query, startDate: fmt(weekAgo), endDate: fmt(now) } }];

// 📊 LLM: Classify New Senders — [PRODUCT-PAID] Weekly Bank Detector
// Reads LLM URL/model from ⚙️ Config; fixes node name references
const config = $('⚙️ Config').first().json._config;
const items = $input.all();
const knownRaw = $('📋 Fetch Known Institution Domains').first().json.domains;
const knownDomains = new Set(Array.isArray(knownRaw) ? knownRaw : []);
const queryInfo = $('🔧 Build Weekly Gmail Search').first().json;

const domainEmails = {};
for (const item of items) {
  const from = String(item.json.from || item.json.From || '');
  const m = from.match(/@([^>"'\s]+)/);
  if (!m) continue;
  const domain = m[1].toLowerCase();
  if (!domainEmails[domain]) domainEmails[domain] = { emails: [], from, subject: String(item.json.subject || item.json.Subject || '') };
  domainEmails[domain].emails.push(item.json);
}

const newDomains = Object.keys(domainEmails).filter(d => !knownDomains.has(d));
const classified = [];
const escSQL = (s) => String(s || '').replace(/'/g, "''");

for (const domain of newDomains) {
  const info = domainEmails[domain];
  const prompt = 'Analyze this email sender and determine if from a financial institution.\nFrom: ' + info.from + '\nSubject: ' + info.subject + '\nReturn ONLY JSON: {"is_financial":true/false,"institution_type":"bank|insurance|investment|ewallet|government|payment_processor|other|not_financial","institution_name":"Name","confidence":0.0-1.0}';
  try {
    const resp = await this.helpers.httpRequestWithAuthentication.call(this, 'openAiApi', {
      method: 'POST',
      url: config.llmBaseUrl,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: config.llmModel, max_tokens: 200, messages: [{ role: 'user', content: prompt }] })
    });
    const parsed = typeof resp === 'string' ? JSON.parse(resp) : resp;
    const text = parsed?.choices?.[0]?.message?.content || '';
    const jsonM = text.match(/\{[\s\S]*?\}/);
    const cls = jsonM ? JSON.parse(jsonM[0]) : { is_financial: false };
    if (cls.is_financial) {
      classified.push({ domain, name: escSQL(cls.institution_name || domain), type: escSQL(cls.institution_type || 'other'), count: info.emails.length, confidence: cls.confidence || 0.5 });
    }
  } catch (e) { /* skip errors */ }
}

let insertQuery = 'SELECT 1;';
if (classified.length > 0) {
  const values = classified.map(c => "('" + escSQL(c.domain) + "','" + c.name + "','" + c.type + "'," + c.count + "," + c.confidence + ")").join(',');
  insertQuery = "INSERT INTO fraud_detection.discovered_institutions (email_domain, institution_name, institution_type, email_count, confidence_score) VALUES " + values + " ON CONFLICT (email_domain) DO UPDATE SET institution_name = EXCLUDED.institution_name, institution_type = EXCLUDED.institution_type, email_count = fraud_detection.discovered_institutions.email_count + EXCLUDED.email_count, last_seen = CURRENT_DATE, updated_at = NOW();";
}

let html = '<h2>Weekly Institution Discovery</h2>';
html += '<p><b>Period:</b> ' + queryInfo.startDate + ' to ' + queryInfo.endDate + '</p>';
html += '<p><b>Emails scanned:</b> ' + items.length + ' | <b>Unique domains:</b> ' + Object.keys(domainEmails).length + ' | <b>Known:</b> ' + (Object.keys(domainEmails).length - newDomains.length) + ' | <b>New senders:</b> ' + newDomains.length + '</p>';
html += '<p><b>New financial institutions:</b> ' + classified.length + '</p>';
if (classified.length > 0) {
  html += '<table border="1" cellpadding="5" style="border-collapse:collapse;"><tr style="background:#eee;"><th>Name</th><th>Type</th><th>Domain</th><th>Emails</th><th>Confidence</th></tr>';
  for (const c of classified) { html += '<tr><td>' + c.name + '</td><td>' + c.type + '</td><td>' + c.domain + '</td><td>' + c.count + '</td><td>' + Math.round(c.confidence * 100) + '%</td></tr>'; }
  html += '</table>';
} else { html += '<p>No new financial institutions discovered this week.</p>'; }
html += '<p style="color:gray;font-size:11px;">Workflow: [PRODUCT-PAID] Weekly Bank Detector @ ' + config.n8nDomain + '</p>';

return [{ json: { insertQuery, subject: 'Weekly Discovery: ' + classified.length + ' new institutions (' + queryInfo.startDate + ' - ' + queryInfo.endDate + ')', htmlBody: html, newCount: classified.length } }];

