// Build Query — [PRODUCT-PAID] Finance Dashboard
// Pure SQL output for native PostgreSQL node (no SSH)
// Parameterized category update (SQL injection fix)
const q = $input.first().json.query || {};

// Handle category update action
if (q.action === 'update_category') {
  const VALID_CATEGORIES = ['food','shopping','transport','transfer','entertainment','investment','utilities','health','education','travel','gifts_occasions','insurance'];
  const id = parseInt(q.id);
  const category = (q.category || '').replace(/[^a-z_]/g, '');
  if (!id || id <= 0 || !VALID_CATEGORIES.includes(category)) {
    return [{json: {action: 'update', error: true}}];
  }
  return [{json: {
    action: 'update',
    updateSql: "UPDATE fraud_detection.transaction_entity SET purchase_category=$1 WHERE id=$2 RETURNING id,purchase_category",
    updateCategory: category,
    updateId: id
  }}];
}

// Normal query mode
const p = q.period || 'this_month';
const now = new Date();
let sd, ed = now.toISOString().split('T')[0];

if (p === 'this_week') {
  const d = new Date(now); d.setDate(d.getDate() - ((d.getDay() + 6) % 7));
  sd = d.toISOString().split('T')[0];
} else if (p === '3_months') {
  const d = new Date(now); d.setMonth(d.getMonth() - 3);
  sd = d.toISOString().split('T')[0];
} else if (p === '6_months') {
  const d = new Date(now); d.setMonth(d.getMonth() - 6);
  sd = d.toISOString().split('T')[0];
} else if (p === '12_months') {
  const d = new Date(now); d.setMonth(d.getMonth() - 12);
  sd = d.toISOString().split('T')[0];
} else if (p === '24_months') {
  const d = new Date(now); d.setMonth(d.getMonth() - 24);
  sd = d.toISOString().split('T')[0];
} else if (p === '36_months') {
  const d = new Date(now); d.setMonth(d.getMonth() - 36);
  sd = d.toISOString().split('T')[0];
} else if (p === 'custom') {
  sd = (q.from && /^\d{4}-\d{2}-\d{2}$/.test(q.from)) ? q.from : '2026-01-01';
  ed = (q.to && /^\d{4}-\d{2}-\d{2}$/.test(q.to)) ? q.to : ed;
} else {
  sd = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-01';
}

const w = "transaction_date>='" + sd + " 00:00:00' AND transaction_date<='" + ed + " 23:59:59'";
const ws = "transaction_type='SPENDING' AND " + w;

const sql = "SELECT json_build_object("
  + "'summary',(SELECT json_build_object("
  + "'total',COUNT(*),"
  + "'total_spending',COALESCE(SUM(amount)FILTER(WHERE transaction_type='SPENDING'),0),"
  + "'flagged',(SELECT COUNT(*)FROM fraud_detection.transaction_fraud_status WHERE is_flagged=true),"
  + "'avg_amount',COALESCE(ROUND(AVG(amount)::numeric,2),0),"
  + "'max_spending',COALESCE(MAX(amount)FILTER(WHERE transaction_type='SPENDING'),0),"
  + "'daily_rate',COALESCE(ROUND((SUM(amount)FILTER(WHERE transaction_type='SPENDING')/GREATEST((CURRENT_DATE-DATE('" + sd + "'))::int,1))::numeric,2),0),"
  + "'institutions',COUNT(DISTINCT bank),"
  + "'dividends',COALESCE(SUM(amount)FILTER(WHERE transaction_type='DIVIDEND'),0),"
  + "'total_income',COALESCE(SUM(amount)FILTER(WHERE transaction_type IN('TRANSFER_IN','DIVIDEND')),0)"
  + ")FROM fraud_detection.transaction_entity WHERE " + w + "),"

  + "'spending_trend',COALESCE((SELECT json_agg(row_to_json(q))FROM("
  + "SELECT r.day,r.total,"
  + "(SELECT json_agg(json_build_object('m',sub.merchant,'a',sub.amount))"
  + " FROM(SELECT COALESCE(t2.merchant,'Unknown')as merchant,ROUND(t2.amount::numeric,2)as amount"
  + " FROM fraud_detection.transaction_entity t2 WHERE t2.transaction_type='SPENDING'"
  + " AND to_char(t2.transaction_date,'YYYY-MM-DD')=r.day AND " + w
  + " ORDER BY t2.amount DESC LIMIT 5)sub)as merchants"
  + " FROM(SELECT to_char(transaction_date,'YYYY-MM-DD')as day,ROUND(SUM(amount)::numeric,2)as total"
  + " FROM fraud_detection.transaction_entity WHERE " + ws
  + " GROUP BY to_char(transaction_date,'YYYY-MM-DD'))r ORDER BY r.day"
  + ")q),'[]'::json),"

  + "'transaction_types',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT transaction_type as type,COUNT(*)as count,ROUND(SUM(amount)::numeric,2)as total "
  + "FROM fraud_detection.transaction_entity WHERE " + w
  + " GROUP BY transaction_type ORDER BY total DESC"
  + ")r),'[]'::json),"

  + "'spending_by_category',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT COALESCE(purchase_category,'uncategorized')as category,ROUND(SUM(amount)::numeric,2)as total "
  + "FROM fraud_detection.transaction_entity WHERE " + ws
  + " GROUP BY purchase_category ORDER BY total DESC"
  + ")r),'[]'::json),"

  + "'spending_by_bank',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT bank,ROUND(SUM(amount)::numeric,2)as total "
  + "FROM fraud_detection.transaction_entity WHERE " + ws
  + " GROUP BY bank ORDER BY total DESC"
  + ")r),'[]'::json),"

  + "'top_merchants',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT COALESCE(merchant,'Unknown')as merchant,ROUND(SUM(amount)::numeric,2)as total "
  + "FROM fraud_detection.transaction_entity WHERE " + ws
  + " GROUP BY merchant ORDER BY total DESC LIMIT 10"
  + ")r),'[]'::json),"

  + "'flagged_items',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT t.id,t.bank,t.merchant,t.amount,t.currency,t.transaction_type,"
  + "to_char(t.transaction_date,'YYYY-MM-DD HH24:MI')as transaction_date,"
  + "fs.flag_reason,COALESCE(fs.risk_score,0)as risk_score,"
  + "CASE WHEN fs.is_confirmed_fraud IS NULL THEN 'pending' WHEN fs.is_confirmed_fraud THEN 'fraud' ELSE 'legit' END as status "
  + "FROM fraud_detection.transaction_entity t "
  + "JOIN fraud_detection.transaction_fraud_status fs ON fs.transaction_id=t.id "
  + "WHERE fs.is_flagged=true ORDER BY t.transaction_date DESC LIMIT 20"
  + ")r),'[]'::json),"

  + "'income_items',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT t.id,t.bank,t.merchant,t.amount,t.currency,t.transaction_type,"
  + "to_char(t.transaction_date,'YYYY-MM-DD HH24:MI')as transaction_date "
  + "FROM fraud_detection.transaction_entity t "
  + "WHERE t.transaction_type IN('TRANSFER_IN','DIVIDEND') AND " + w
  + " ORDER BY t.transaction_date DESC LIMIT 20"
  + ")r),'[]'::json),"

  + "'recent',COALESCE((SELECT json_agg(r)FROM("
  + "SELECT t.id,t.bank,t.merchant,t.amount,t.currency,t.transaction_type,"
  + "t.purchase_category,t.payment_method,"
  + "to_char(t.transaction_date,'YYYY-MM-DD HH24:MI')as transaction_date,"
  + "COALESCE(fs.is_flagged,false)as is_flagged,"
  + "COALESCE(fs.risk_score,0)as risk_score "
  + "FROM fraud_detection.transaction_entity t "
  + "LEFT JOIN fraud_detection.transaction_fraud_status fs ON fs.transaction_id=t.id "
  + "ORDER BY t.transaction_date DESC LIMIT 50"
  + ")r),'[]'::json)"
  + ")as data";

return [{json: {action: 'query', sql, period: p, startDate: sd, endDate: ed}}];

