function esc(str) {
  if (!str) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function fmt(n) {
  if (n == null) return '0';
  return Number(n).toLocaleString();
}

function fmtCur(n) {
  if (n == null) return '<span class="amount" data-v="$0.00">$0.00</span>';
  const v = '$' + Number(n).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  return '<span class="amount" data-v="' + v + '">' + v + '</span>';
}

function truncate(s, len) {
  if (!s) return '';
  s = String(s);
  return s.length > len ? s.substring(0, len) + '\u2026' : s;
}

