let kpiIndex = 0;
function kpiCard(label, value, accent, subtitle) {
  const delay = kpiIndex * 0.06;
  kpiIndex++;
  return `<div class="kpi" style="border-left:3px solid ${accent};animation-delay:${delay}s">
    <div class="kpi-label">${esc(label)}</div>
    <div class="kpi-value">${value}</div>
    ${subtitle ? `<div class="kpi-sub">${subtitle}</div>` : ''}
  </div>`;
}

// Risk score badge helper
function riskBadge(score) {
  if (score == null || score === 0) return '<span class="badge" style="background:#21262d;color:#484f58;border:1px solid #30363d">-</span>';
  let color, bg;
  if (score >= 70) { color = '#ff4757'; bg = '#ff475718'; }
  else if (score >= 50) { color = '#ffb800'; bg = '#ffb80018'; }
  else if (score >= 30) { color = '#fb923c'; bg = '#fb923c18'; }
  else { color = '#00e5a0'; bg = '#00e5a018'; }
  return `<span class="badge" style="background:${bg};color:${color};border:1px solid ${color}30">${score}</span>`;
}

