      options:{indexAxis:'y',responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:barTooltip},scales:{x:{beginAtZero:true,grid:{color:'rgba(33,38,45,0.4)'},ticks:{color:'#8b949e',font:{size:11},callback:privTickCb}},y:{grid:{display:false},ticks:{color:'#8b949e',font:{size:11,family:"'JetBrains Mono',monospace"}}}}}
    });
  })();
`;

// Assemble full HTML
const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Smart Finance Tracker \u2014 Dashboard</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;700&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{font-family:'JetBrains Mono',monospace;font-weight:400;font-size:13px;color:#e6edf3;background:#06080f;line-height:1.5;-webkit-font-smoothing:antialiased}
h1,h3{font-family:'Outfit',sans-serif}
h1{font-size:28px;font-weight:700;color:#e6edf3;letter-spacing:-0.02em}
h3{font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:0.08em;color:#8b949e;margin-bottom:16px}
a{color:#00d4ff;text-decoration:none}

.accent-bar{height:3px;background:linear-gradient(90deg,#00e5a0 0%,#00d4ff 50%,#a78bfa 100%)}
.wrap{max-width:1360px;margin:0 auto;padding:28px 32px 48px}
.header{display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:12px;margin-bottom:20px}
.header-left{flex:1;min-width:240px}
.dash-label{font-family:'JetBrains Mono',monospace;font-size:11px;font-weight:500;letter-spacing:0.12em;color:#484f58;text-transform:uppercase;margin-bottom:4px}
.subtitle{font-size:12px;color:#484f58;margin-top:4px;font-weight:400}
.header-right{display:flex;align-items:center;gap:8px;flex-wrap:wrap}

.pill{display:inline-block;padding:6px 16px;border-radius:20px;font-size:11px;font-weight:500;font-family:'JetBrains Mono',monospace;color:#8b949e;background:transparent;border:1px solid #21262d;text-decoration:none;transition:all .2s}
.pill:hover{border-color:#00e5a0;color:#00e5a0}
.pill-active{background:#00e5a012;color:#00e5a0;border-color:#00e5a0;box-shadow:0 0 12px rgba(0,229,160,0.15)}

.date-row{display:flex;align-items:center;gap:10px;margin-bottom:20px;flex-wrap:wrap}
.date-row label{font-size:11px;color:#484f58;font-weight:500;letter-spacing:0.04em}
.date-row input[type="date"]{padding:6px 10px;border:1px solid #21262d;border-radius:8px;font-size:12px;font-family:'JetBrains Mono',monospace;color:#e6edf3;background:#0d1117}
.date-row input[type="date"]:focus{outline:none;border-color:#00e5a0;box-shadow:0 0 0 2px rgba(0,229,160,0.12)}
.date-row .btn-apply{padding:6px 18px;border:none;border-radius:8px;background:#00e5a0;color:#06080f;font-size:12px;font-weight:600;cursor:pointer;font-family:'Outfit',sans-serif;transition:all .2s}
.date-row .btn-apply:hover{background:#33eeb6;box-shadow:0 0 12px rgba(0,229,160,0.3)}

.refresh-toggle{display:flex;align-items:center;gap:6px;font-size:11px;color:#484f58;cursor:pointer;user-select:none}
.refresh-toggle input{accent-color:#00e5a0}
.privacy-switch{display:inline-flex;align-items:center;gap:10px;padding:5px 14px;border-radius:20px;font-size:11px;font-family:'JetBrains Mono',monospace;font-weight:600;color:#8b949e;letter-spacing:0.08em;text-transform:uppercase;cursor:pointer;user-select:none;border:1px solid #21262d;transition:color .2s,border-color .2s,box-shadow .2s}
.privacy-switch:hover{border-color:#30363d;color:#e6edf3}
.privacy-switch input{position:absolute;opacity:0;width:0;height:0;pointer-events:none}
.privacy-switch .pill{position:relative;display:inline-block;width:30px;height:16px;background:#21262d;border-radius:16px;transition:background .2s;flex-shrink:0}
.privacy-switch .pill::after{content:'';position:absolute;top:2px;left:2px;width:12px;height:12px;background:#e6edf3;border-radius:50%;transition:transform .2s,background .2s}
.privacy-switch input:checked ~ .pill{background:#00e5a0}
.privacy-switch input:checked ~ .pill::after{transform:translateX(14px);background:#06080f}
body.privacy-mode .privacy-switch{color:#00e5a0;border-color:#00e5a0;box-shadow:0 0 12px rgba(0,229,160,0.18)}
body.privacy-mode .amount{position:relative;color:transparent !important;text-shadow:none !important}
body.privacy-mode .amount::after{content:'***';position:absolute;top:0;left:0;right:0;bottom:0;color:#e6edf3;font:inherit;letter-spacing:inherit;text-align:inherit;display:flex;align-items:center}
body.privacy-mode .td-right .amount::after{justify-content:flex-end}

.kpi-grid{display:grid;grid-template-columns:repeat(6,1fr);gap:14px;margin-bottom:24px}
.kpi{background:rgba(13,17,23,0.8);backdrop-filter:blur(12px);border:1px solid rgba(33,38,45,0.6);border-radius:14px;padding:18px 20px;animation:fadeSlideIn 0.5s ease-out both;transition:transform .2s,box-shadow .2s}
.kpi:hover{transform:translateY(-2px);box-shadow:0 0 24px rgba(0,229,160,0.06)}
.kpi-label{font-size:10px;font-weight:500;color:#484f58;text-transform:uppercase;letter-spacing:0.06em;margin-bottom:8px}
.kpi-value{font-family:'Outfit',sans-serif;font-size:24px;font-weight:700;color:#e6edf3;letter-spacing:-0.02em}
.kpi-sub{font-size:11px;color:#8b949e;margin-top:4px}

.card{background:rgba(13,17,23,0.8);backdrop-filter:blur(12px);border:1px solid rgba(33,38,45,0.6);border-radius:14px;padding:24px;margin-bottom:24px;transition:transform .2s,box-shadow .2s}
.card:hover{box-shadow:0 0 24px rgba(0,229,160,0.04)}
.anim{animation:fadeSlideIn 0.5s ease-out both}

.chart-row-2fr1fr{display:grid;grid-template-columns:2fr 1fr;gap:20px;margin-bottom:24px}
.chart-row-2fr1fr .card{margin-bottom:0}
.chart-row-3col{display:grid;grid-template-columns:1fr 1fr 1fr;gap:20px;margin-bottom:24px}
.chart-row-3col .card{margin-bottom:0}
.chart-wrap{position:relative}

@keyframes fadeSlideIn{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}

.table-header{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px;margin-bottom:12px}
.table-header h3{margin-bottom:0}
.search-input{padding:7px 14px;border:1px solid #21262d;border-radius:8px;font-size:12px;font-family:'JetBrains Mono',monospace;color:#e6edf3;width:260px;background:#0d1117;transition:border-color .2s}
.search-input:focus{outline:none;border-color:#00e5a0;box-shadow:0 0 0 2px rgba(0,229,160,0.12)}
.search-input::placeholder{color:#484f58}
.table-wrap{overflow-x:auto}
.data-table{width:100%;border-collapse:collapse;font-size:12px}
.data-table th{text-align:left;padding:10px 12px;font-weight:500;color:#484f58;font-size:10px;text-transform:uppercase;letter-spacing:0.06em;border-bottom:1px solid #21262d;white-space:nowrap}
.data-table td{padding:10px 12px;border-bottom:1px solid #161b22;color:#e6edf3}
.data-table tbody tr:nth-child(odd){background:rgba(13,17,23,0.5)}
.data-table tbody tr:nth-child(even){background:rgba(22,27,34,0.5)}
.data-table tbody tr:hover{background:rgba(0,229,160,0.04)}
.td-time{white-space:nowrap;font-size:11px;color:#8b949e}
.td-right{text-align:right;font-variant-numeric:tabular-nums}
.td-center{text-align:center}
.badge{display:inline-block;padding:2px 10px;border-radius:10px;font-size:10px;font-weight:500;white-space:nowrap}
.dot{display:inline-block;width:8px;height:8px;border-radius:50%}
.dot-red{background:#ff4757;box-shadow:0 0 6px rgba(255,71,87,0.4)}
.dot-muted{background:#21262d}
.no-data{color:#484f58;text-align:center;padding:40px 0;font-size:13px}

.cat-select{font-family:'JetBrains Mono',monospace;font-size:11px;padding:3px 6px;border:1px solid #21262d;border-radius:6px;background:#0d1117;color:#e6edf3;cursor:pointer;transition:all .2s}
.cat-select:hover{border-color:#00e5a0}
.cat-select:focus{outline:none;border-color:#00e5a0;box-shadow:0 0 0 2px rgba(0,229,160,0.15)}
.cat-select.saved{background:#00e5a015;border-color:#00e5a0;color:#00e5a0}
.cat-select.error{background:#ff475715;border-color:#ff4757;color:#ff4757}
.cat-select option{background:#0d1117;color:#e6edf3}

.flagged-card{border-left:3px solid #ff4757}
.income-card{border-left:3px solid #00e5a0}

.footer{text-align:center;padding:24px 0 0;font-size:11px;color:#484f58;letter-spacing:0.04em}

::-webkit-scrollbar{width:6px;height:6px}
::-webkit-scrollbar-track{background:#06080f}
::-webkit-scrollbar-thumb{background:#21262d;border-radius:3px}
::-webkit-scrollbar-thumb:hover{background:#30363d}

@media(max-width:1100px){
  .kpi-grid{grid-template-columns:repeat(3,1fr)}
  .chart-row-2fr1fr,.chart-row-3col{grid-template-columns:1fr}
}
@media(max-width:640px){
  .kpi-grid{grid-template-columns:repeat(2,1fr)}
  .header{flex-direction:column}
  .search-input{width:100%}
  .wrap{padding:16px}
}
</style>
</head>
<body>
<div class="accent-bar"></div>
<div class="wrap">
  <div class="header">
    <div class="header-left">
      <div class="dash-label">Dashboard</div>
      <h1>Smart Finance Tracker</h1>
      <div class="subtitle">${esc(periodLabel)}${dateRangeLabel ? ' &middot; ' + esc(dateRangeLabel) : ''}</div>
    </div>
    <div class="header-right">
      ${pills}
      <label class="refresh-toggle"><input type="checkbox" id="autoRefresh" onchange="toggleAutoRefresh()"> Auto-refresh</label>
      <label class="privacy-switch"><input type="checkbox" id="privacyMode" onchange="togglePrivacy()">Privacy<span class="pill"></span></label>
    </div>
  </div>

  <div class="date-row">
    <label>Custom range:</label>
    <input type="date" id="customStart" value="${esc(startDate)}">
    <span style="color:#484f58">to</span>
    <input type="date" id="customEnd" value="${esc(endDate)}">
    <button class="btn-apply" onclick="applyCustomRange()">Apply</button>
  </div>

  ${kpis}
  ${charts1}
  ${charts2}
  ${flaggedHtml}
  ${incomeHtml}
  ${recentTable}

  <div class="footer">Smart Finance Tracker v1.0 &middot; Powered by n8n &middot; ${esc(now)}</div>
</div>

<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
<script>
Chart.defaults.color = '#8b949e';
Chart.defaults.borderColor = '#21262d';
Chart.defaults.font.family = "'JetBrains Mono', monospace";

${chartScript}

function filterFinTable() {
  var q = (document.getElementById('finSearch') || {}).value || '';
  q = q.toLowerCase();
  var rows = document.querySelectorAll('#finTable tbody tr');
  rows.forEach(function(row) {
    var searchText = row.getAttribute('data-search') || '';
    row.style.display = (!q || searchText.indexOf(q) !== -1) ? '' : 'none';
  });
}

function updateCategory(el) {
  var id = el.getAttribute('data-id');
  var category = el.value;
  el.disabled = true;
  fetch('?action=update_category&id=' + id + '&category=' + category)
    .then(function(r) { return r.text(); })
    .then(function(text) {
      try { var j = JSON.parse(text); if (j.success) { el.className = 'cat-select saved'; } else { el.className = 'cat-select error'; } }
      catch(e) { el.className = 'cat-select error'; }
      el.disabled = false;
      setTimeout(function() { el.className = 'cat-select'; }, 2000);
    })
    .catch(function() { el.className = 'cat-select error'; el.disabled = false; setTimeout(function() { el.className = 'cat-select'; }, 2000); });
}

function applyCustomRange() {
  var s = document.getElementById('customStart').value;
  var e = document.getElementById('customEnd').value;
  if (s && e) {
    window.location.href = '?period=custom&from=' + s + '&to=' + e;
  }
}

var refreshTimer = null;
function toggleAutoRefresh() {
  var checked = document.getElementById('autoRefresh').checked;
  if (checked) {
    refreshTimer = setTimeout(function() { window.location.reload(); }, 60000);
  } else {
    if (refreshTimer) clearTimeout(refreshTimer);
    refreshTimer = null;
  }
}

var PRIVACY_KEY = 'financeDashboard.privacyMode';
function refreshCharts() {
  if (!window.Chart) return;
  ['spendChart','txnDonut','catSpendBar','merchantBar','bankBar'].forEach(function(id){
    var c = Chart.getChart(id);
    if (c) c.update('none');
  });
}
function togglePrivacy() {
  var on = document.getElementById('privacyMode').checked;
  document.body.classList.toggle('privacy-mode', on);
  try { localStorage.setItem(PRIVACY_KEY, on ? '1' : '0'); } catch(e) {}
  refreshCharts();
}
(function initPrivacy(){
  var saved = false;
  try { saved = localStorage.getItem(PRIVACY_KEY) === '1'; } catch(e) {}
  var cb = document.getElementById('privacyMode');
  if (cb) cb.checked = saved;
  if (saved) {
    document.body.classList.add('privacy-mode');
    refreshCharts();
  }
})();

(function(){
  var cards = document.querySelectorAll('.anim');
  for(var i=0;i<cards.length;i++){
    cards[i].style.animationDelay = (0.08 * i) + 's';
  }
})();
</script>
</body>
</html>`;

return [{ json: { html } }];
